@startuml
skinparam classAttributeIconSize 0
left to right direction

abstract class Book << (A,#bfe7ea) >> {
  +BookCategory
  +Page
  +Author
}

abstract class BookFactory << (A,#bfe7ea) >> {
  +GetBook()
}

class FantasticFactory << (C,#b9d7b9) >> {
  -_page
  -_author
  --
  +FantasticFactory()
}

class ScienceFictionFactory << (C,#b9d7b9) >> {
  -_page
  -_author
  --
  +ScienceFictionFactory()
}

class FantasticBook << (C,#b9d7b9) >> {
  -_bookCategory
  -_page
  -_author
  --
  +FantasticBook()
}

class ScienceFictionBook << (C,#b9d7b9) >> {
  -_bookCategory
  -_page
  -_author
  --
  +ScienceFictionBook()
}

FantasticFactory ..> FantasticBook
ScienceFictionFactory ..> ScienceFictionBook

FantasticFactory --|> BookFactory
ScienceFictionFactory --|> BookFactory

FantasticBook --|> Book
ScienceFictionBook --|> Book
@enduml
